import { useState, useEffect, useRef } from 'react'
import { ChevronDownIcon } from '@heroicons/react/20/solid'
import { useAuth } from '../context/AuthContext'
import config from '../config/config'

export function SearchResult({ result, onAddToList }) {
  const { isAuthenticated } = useAuth();
  const [isOpen, setIsOpen] = useState(false)
  const mapRef = useRef(null)
  const mapInstanceRef = useRef(null)

  const toggleAccordion = () => setIsOpen(!isOpen)

  const handleDDGSearch = () => {
    const searchQuery = encodeURIComponent(`${result.Destination} ${result.Country}`);
    window.open(`https://duckduckgo.com/?q=${searchQuery}`, '_blank');
  };

  useEffect(() => {
    if (isOpen && mapRef.current && !mapInstanceRef.current) {
      const initMap = async () => {
        try {
          const response = await fetch(`${config.api.baseUrl}/api/destinations/${result._id}/coordinates`)
          const coords = await response.json()

          const map = L.map(mapRef.current).setView([coords.Latitude, coords.Longitude], 13)
          L.tileLayer('https://tile.openstreetmap.org/{z}/{x}/{y}.png', {
            maxZoom: 19,
            attribution: '&copy; OpenStreetMap'
          }).addTo(map)

          L.marker([coords.Latitude, coords.Longitude]).addTo(map)
          mapInstanceRef.current = map
        } catch (error) {
          console.error('Error loading map:', error)
        }
      }

      initMap()
    }

    // Cleanup function
    return () => {
      if (mapInstanceRef.current) {
        mapInstanceRef.current.remove()
        mapInstanceRef.current = null
      }
    }
  }, [isOpen, result._id])

  return (
    <div className="border border-soft-blue-200 dark:border-gray-700 rounded-2xl mb-4 bg-white dark:bg-gray-800 shadow-sm">
      <button 
        onClick={toggleAccordion}
        className="flex items-center justify-between w-full p-5 text-left font-medium text-soft-blue-700 dark:text-gray-300 hover:bg-soft-blue-50 dark:hover:bg-gray-700 focus:outline-none focus:ring-2 focus:ring-soft-blue-500 rounded-2xl transition-colors"
      >
        <span>{result.Destination} ({result.Country}, {result.Region})</span>
        <ChevronDownIcon className={`w-5 h-5 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
      </button>
      {isOpen && (
        <div className="p-6 bg-cream-50 dark:bg-gray-900 text-soft-blue-700 dark:text-gray-300 space-y-3 text-left rounded-b-2xl">
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Destination:</strong> {result.Destination}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Country:</strong> {result.Country}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Region:</strong> {result.Region}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">ID:</strong> {result._id}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Category:</strong> {result.Category}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Latitude:</strong> {result.Latitude}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Longitude:</strong> {result.Longitude}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Approximate Annual Tourists:</strong> {result['Approximate Annual Tourists']}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Currency:</strong> {result.Currency}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Majority Religion:</strong> {result['Majority Religion']}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Famous Foods:</strong> {result['Famous Foods']}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Language:</strong> {result.Language}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Best Time to Visit:</strong> {result['Best Time to Visit']}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Cost of Living:</strong> {result['Cost of Living']}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Safety:</strong> {result.Safety}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Cultural Significance:</strong> {result['Cultural Significance']}</p>
          <p className="text-sm"><strong className="text-soft-blue-800 dark:text-gray-100">Description:</strong> {result.Description}</p>
          <div 
            ref={mapRef} 
            className="w-full h-[300px] mt-4 rounded-xl"
          />

          <div className="flex gap-3 mt-6">
            <button
              onClick={handleDDGSearch}
              className="flex-1 border border-soft-blue-600 dark:border-soft-blue-500 text-soft-blue-600 dark:text-soft-blue-400 py-2.5 px-4 rounded-full hover:bg-soft-blue-50 dark:hover:bg-gray-700 focus:ring-2 focus:ring-soft-blue-500 focus:ring-offset-2 transition-colors text-sm font-medium"
            >
              Search on DuckDuckGo
            </button>

            {isAuthenticated && (
              <button
                onClick={() => onAddToList(result)}
                className="flex-1 bg-soft-blue-600 dark:bg-soft-blue-500 text-white py-2.5 px-4 rounded-full hover:bg-soft-blue-700 dark:hover:bg-soft-blue-600 focus:ring-2 focus:ring-soft-blue-500 focus:ring-offset-2 transition-colors text-sm font-medium"
              >
                Add to List
              </button>
            )}
          </div>
        </div>
      )}
    </div>
  )
}
